/**
 * Extracts the YouTube URL and 11-char video ID from a Slack slash command payload.
 * Tailored for /rippit (removes the command prefix).
 */

// Matches typical YouTube forms: watch?v=, youtu.be/, shorts/, embed/
const YT_RE = /(?:youtube\.com\/watch\?v=|youtu\.be\/|shorts\/|embed\/)([A-Za-z0-9_-]{11})/i;

function toItem(inputJson = {}) {
  // Slack sends the text in body.text; fall back to text for test runs
  const raw = (inputJson?.body?.text ?? inputJson?.text ?? '').toString();

  // Remove the "/rippit" command prefix (and any extra spaces)
  const text = raw.replace(/^\/rippit\s*/, '').trim();

  // Try to grab the first URL if user pasted text + link; otherwise treat text as URL
  const urlMatch = text.match(/https?:\/\/\S+/);
  const url = urlMatch ? urlMatch[0] : text;

  // Extract the canonical 11-char video ID (null if not matched)
  const idMatch = url.match(YT_RE);
  const videoId = idMatch ? idMatch[1] : null;

  return { json: { text, videoUrl: url, videoId } };
}

// Support both single-item and aggregated runs
const itemsIn = $input.all();
return itemsIn.length ? itemsIn.map(i => toItem(i.json)) : [toItem($json)];

// Get the duration from the API response
const duration = $input.item.json.items[0].contentDetails.duration;

// Parse ISO 8601 duration format (e.g., PT10M30S, PT1H5M, PT45S)
const match = duration.match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/);

const hours = parseInt(match[1] || 0);
const minutes = parseInt(match[2] || 0);
const seconds = parseInt(match[3] || 0);

// Calculate total minutes
const totalMinutes = hours * 60 + minutes + seconds / 60;

// Get data from Extract YouTube node
const extractYouTubeNode = $('Extract YouTube video ID').first();

// Check if video is too long
if (totalMinutes > 10) {
  // Return error flag instead of throwing
  return {
    json: {
      error: true,
      errorMessage: `Video is too long: ${Math.round(totalMinutes)} minutes. Maximum allowed is 10 minutes.`,
      videoId: extractYouTubeNode.json.videoId,
      videoUrl: extractYouTubeNode.json.videoUrl
    }
  };
}

// Pass through for valid videos
return {
  json: {
    error: false,
    videoId: extractYouTubeNode.json.videoId,
    videoUrl: extractYouTubeNode.json.videoUrl,
    durationMinutes: Math.round(totalMinutes * 10) / 10
  }
};

// Read the mode that Edit Fields already decided
const mode = ($items('Normalize Slack payload', 0, 0)?.json?.mode) || 'summary';

// Pass the transcript text from the AssemblyAI HTTP Request node ($json.text)
return [{
  json: {
    transcript: $json.text ?? '',
    mode
  }
}];
